const Calendar = ({ posts, onDateClick, activeDate }) => {
  const today = useMemo(() => new Date(), []);
  const [viewYear, setViewYear] = useState(today.getFullYear());
  const [viewMonth, setViewMonth] = useState(today.getMonth());
  const postDateMap = useMemo(() => {
    const map = {};
    posts.forEach(p => {
      if (p.date) {
        const d = new Date(p.date);
        const key = `${d.getFullYear()}-${d.getMonth()}-${d.getDate()}`;
        if (!map[key]) map[key] = [];
        map[key].push(p);
      }
    });
    return map;
  }, [posts]);
  const days = useMemo(() => getCalendarDays(viewYear, viewMonth), [viewYear, viewMonth]);
  const monthNames = ['一月', '二月', '三月', '四月', '五月', '六月', '七月', '八月', '九月', '十月', '十一月', '十二月'];
  const prevMonth = useCallback(() => { if (viewMonth === 0) { setViewYear(y => y - 1); setViewMonth(11); } else setViewMonth(m => m - 1); }, [viewMonth]);
  const nextMonth = useCallback(() => { if (viewMonth === 11) { setViewYear(y => y + 1); setViewMonth(0); } else setViewMonth(m => m + 1); }, [viewMonth]);
  return (
    <div className="sidebar-section">
      <h3>日历</h3>
      <div className="calendar-nav">
        <button onClick={prevMonth}>{'<'}</button>
        <span className="month-label">{viewYear}年 {monthNames[viewMonth]}</span>
        <button onClick={nextMonth}>{'>'}</button>
      </div>
      <div className="calendar-grid">
        {['日', '一', '二', '三', '四', '五', '六'].map(d => <div key={d} className="calendar-header">{d}</div>)}
        {days.map((d, i) => {
          const key = `${d.year}-${d.month}-${d.day}`;
          const hasPost = !!postDateMap[key];
          const isToday = d.year === today.getFullYear() && d.month === today.getMonth() && d.day === today.getDate();
          const dateStr = `${d.year}-${String(d.month + 1).padStart(2, '0')}-${String(d.day).padStart(2, '0')}`;
          const isActiveDate = activeDate === dateStr;
          let cls = 'calendar-day';
          if (d.isOtherMonth) cls += ' other-month';
          if (hasPost) cls += ' has-post';
          if (isToday) cls += ' today';
          if (isActiveDate) cls += ' today';
          return (<div key={i} className={cls} onClick={() => hasPost && onDateClick && onDateClick(dateStr)}
            title={hasPost ? `${postDateMap[key].length} 篇文章` : `筛选 ${dateStr}`}>{d.day}</div>);
        })}
      </div>
    </div>
  );
};

