const PostList = ({ posts, activeTag, setActiveTag }) => {
  const [visibleCount, setVisibleCount] = useState(PAGE_SIZE);
  const [loading, setLoading] = useState(false);
  const sentinelRef = useRef(null);
  useEffect(() => { setVisibleCount(PAGE_SIZE); }, [activeTag]);
  useEffect(() => {
    const sentinel = sentinelRef.current;
    if (!sentinel) return;
    const observer = new IntersectionObserver((entries) => {
      if (entries[0].isIntersecting && visibleCount < posts.length && !loading) {
        setLoading(true);
        setTimeout(() => { setVisibleCount(prev => Math.min(prev + PAGE_SIZE, posts.length)); setLoading(false); }, 300);
      }
    }, { rootMargin: '100px' });
    observer.observe(sentinel);
    return () => observer.disconnect();
  }, [visibleCount, posts.length, loading]);
  const visiblePosts = posts.slice(0, visibleCount);
  const hasMore = visibleCount < posts.length;
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
      {visiblePosts.map(article => (
        <article key={article.id} className="card">
          <div style={{ marginBottom: '10px', display: 'flex', gap: '8px', alignItems: 'center', flexWrap: 'wrap' }}>
            {article.category && <span className="category-badge">{article.category}</span>}
            {article.tags && article.tags.map(tag => (
              <span key={tag} className="tag" onClick={(e) => { e.preventDefault(); setActiveTag(tag); }}>{tag}</span>
            ))}
          </div>
          <h2 style={{ fontSize: '1.5rem', marginBottom: '8px' }}>
            <Link to={`/post/${encodePath(article.id)}`}>{article.title}</Link>
          </h2>
          <div style={{ fontSize: '0.875rem', color: 'var(--text-faint)', marginBottom: '12px' }}>{formatDate(article.date)}</div>
          <p style={{ color: 'var(--text-muted)' }}>{article.summary}</p>
        </article>
      ))}
      <div ref={sentinelRef} className="load-more-trigger">
        {hasMore ? (loading ? <div className="load-more-spinner" /> : (
          <button className="load-more-btn" onClick={() => setVisibleCount(prev => Math.min(prev + PAGE_SIZE, posts.length))}>
            加载更多文章 ({posts.length - visibleCount} 篇剩余)
          </button>
        )) : posts.length > 0 ? (
          <span style={{ color: 'var(--text-faint)', fontSize: '0.85rem' }}>已加载全部 {posts.length} 篇文章</span>
        ) : null}
      </div>
    </div>
  );
};

