const useTextHighlighter = (containerRef) => {
  const highlightsRef = useRef([]);
  const fnRef = useRef({});
  const [popup, setPopup] = useState({ show: false, x: 0, y: 0 });
  const selectionRangeRef = useRef(null);

  const saveHighlights = (highlights) => {
    highlightsRef.current = highlights;
    try { localStorage.setItem('blog-highlights', JSON.stringify(highlights)); } catch { }
  };

  const applyHighlightFn = (h) => {
    try {
      const container = containerRef.current;
      if (!container) return false;
      const treeWalker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT, null, false);
      const nodeMap = [];
      let fullText = '';
      let node;
      while ((node = treeWalker.nextNode())) {
        nodeMap.push({ node, start: fullText.length, end: fullText.length + node.textContent.length });
        fullText += node.textContent;
      }
      const idx = fullText.indexOf(h.text);
      if (idx === -1) return false;
      const endIdx = idx + h.text.length;
      let applied = false;
      for (const { node, start, end } of nodeMap) {
        if (end <= idx || start >= endIdx) continue;
        const segStart = Math.max(idx, start) - start;
        const segEnd = Math.min(endIdx, end) - start;
        if (segStart >= segEnd) continue;
        const range = document.createRange();
        range.setStart(node, segStart);
        range.setEnd(node, segEnd);
        const mark = document.createElement('mark');
        mark.style.cssText = `background:${h.color};color:#1a1b1e;padding:0 2px;border-radius:2px;cursor:pointer;`;
        mark.dataset.highlightId = h.id;
        mark.title = '点击移除标注';
        mark.onclick = (e) => { e.stopPropagation(); fnRef.current.removeHighlightFn(h.id); };
        range.surroundContents(mark);
        applied = true;
      }
      return applied;
    } catch { return false; }
  };

  const removeHighlightFn = (id) => {
    const marks = containerRef.current?.querySelectorAll(`mark[data-highlight-id="${id}"]`);
    if (marks) {
      marks.forEach(m => {
        const parent = m.parentNode;
        while (m.firstChild) parent.insertBefore(m.firstChild, m);
        parent.removeChild(m);
        parent.normalize();
      });
    }
    saveHighlights(highlightsRef.current.filter(h => h.id !== id));
  };

  const clearAllHighlights = () => {
    const marks = containerRef.current?.querySelectorAll('mark[data-highlight-id]');
    if (marks) {
      marks.forEach(m => {
        const parent = m.parentNode;
        while (m.firstChild) parent.insertBefore(m.firstChild, m);
        parent.removeChild(m);
        parent.normalize();
      });
    }
    saveHighlights([]);
  };

  fnRef.current = { applyHighlightFn, removeHighlightFn, clearAllHighlights, saveHighlights, containerRef, highlightsRef };

  useEffect(() => {
    const handleMouseUp = (e) => {
      if (e.target.closest('.highlight-popup')) return;
      setTimeout(() => {
        const sel = window.getSelection();
        if (!sel || sel.isCollapsed || !sel.rangeCount) { setPopup(p => p.show ? { ...p, show: false } : p); return; }
        const range = sel.getRangeAt(0);
        const container = containerRef.current;
        if (!container?.contains(range.commonAncestorContainer)) { setPopup(p => p.show ? { ...p, show: false } : p); return; }
        const text = sel.toString().trim();
        if (!text || text.length > 500) { setPopup(p => p.show ? { ...p, show: false } : p); return; }
        selectionRangeRef.current = range.cloneRange();
        setPopup({ show: true, x: e.clientX, y: e.clientY });
      }, 5);
    };
    document.addEventListener('mouseup', handleMouseUp);
    return () => document.removeEventListener('mouseup', handleMouseUp);
  }, [containerRef]);

  const addHighlight = useCallback((color) => {
    let text = '';
    let range = selectionRangeRef.current;
    if (range) { text = range.toString().trim(); }
    if (!text || !range) { setPopup({ show: false, x: 0, y: 0 }); return; }
    const id = Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
    const highlight = { id, text, color };
    fnRef.current.saveHighlights([...fnRef.current.highlightsRef.current, highlight]);
    fnRef.current.applyHighlightFn(highlight);
    setPopup({ show: false, x: 0, y: 0 });
  }, []);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;
    const restore = () => {
      const existing = highlightsRef.current;
      const alreadyApplied = new Set();
      container.querySelectorAll('mark[data-highlight-id]').forEach(m => alreadyApplied.add(m.dataset.highlightId));
      existing.filter(h => !alreadyApplied.has(h.id)).forEach(h => { fnRef.current.applyHighlightFn(h); });
    };
    const timer = setTimeout(restore, 50);
    return () => clearTimeout(timer);
  }, [containerRef]);

  const closePopup = useCallback(() => { setPopup({ show: false, x: 0, y: 0 }); }, []);

  return { popup, addHighlight, closePopup, clearAllHighlights, highlightsCount: highlightsRef.current.length };
};

// ==================== 新 TOC 组件 ====================
/**
 * 使用 github-slugger 提取标题，生成的 id 与 rehypeSlug 保持一致
 */
const extractHeadings = (markdown) => {
  const headings = [];
  const regex = /^(#{1,3})\s+(.+)$/gm;
  const slugger = new GithubSlugger();
  let match;
  while ((match = regex.exec(markdown)) !== null) {
    const text = match[2];
    const id = slugger.slug(text);
    headings.push({ level: match[1].length, text, id });
  }
  return headings;
};

/**
 * 将扁平标题列表转换为嵌套树结构（仅 h1 作为可折叠分组）
 */
const buildTocTree = (headings) => {
  const groups = [];
  let currentGroup = null;

  for (const h of headings) {
    if (h.level === 1) {
      // h1 开启一个新分组
      currentGroup = { heading: h, children: [] };
      groups.push(currentGroup);
    } else if (currentGroup) {
      // h2/h3 归入当前 h1 分组
      currentGroup.children.push(h);
    } else {
      // 没有 h1 时，h2/h3 作为独立项
      groups.push({ heading: null, children: [h] });
    }
  }
  // 如果没有任何 h1，将所有 children 展平
  if (groups.length === 0 && headings.length > 0) {
    groups.push({ heading: null, children: headings });
  }
  return groups;
};

/**
 * 可折叠 TOC 组件，带滚动位置实时追踪
 */
const TOC = ({ headings }) => {
  const [activeId, setActiveId] = useState('');
  const [collapsedMap, setCollapsedMap] = useState({});
  const [sidebarLeft, setSidebarLeft] = useState(0);
  const placeholderRef = useRef(null);
  const tocRef = useRef(null);
  const userScrollingToc = useRef(false);
  const userScrollTimer = useRef(null);

  const groups = useMemo(() => buildTocTree(headings), [headings]);

  // 所有标题项的扁平列表，用于 IntersectionObserver
  const allIds = useMemo(() => {
    const ids = [];
    for (const g of groups) {
      if (g.heading) ids.push(g.heading.id);
      for (const child of g.children) ids.push(child.id);
    }
    return ids;
  }, [groups]);

  // 计算停靠位置
  useEffect(() => {
    const updateLeft = () => {
      if (placeholderRef.current) {
        const rect = placeholderRef.current.getBoundingClientRect();
        setSidebarLeft(rect.left);
      }
    };
    updateLeft();
    window.addEventListener('resize', updateLeft);
    return () => window.removeEventListener('resize', updateLeft);
  }, []);

  // 当 heading 变化时，默认展开所有 h1 组
  useEffect(() => {
    const map = {};
    for (const g of groups) {
      if (g.heading) map[g.heading.id] = false;
    }
    setCollapsedMap(map);
  }, [groups]);

  // IntersectionObserver：追踪滚动位置，高亮当前标题
  // 使用轮询等待 DOM 渲染完成（ReactMarkdown 是异步的）
  useEffect(() => {
    if (allIds.length === 0) return;

    let observer = null;
    let retryCount = 0;
    const MAX_RETRIES = 30;
    let timerId = null;

    const setupObserver = () => {
      const elements = allIds
        .map((id) => document.getElementById(id))
        .filter(Boolean);

      if (elements.length === 0 && retryCount < MAX_RETRIES) {
        retryCount++;
        timerId = setTimeout(setupObserver, 100);
        return;
      }

      if (elements.length > 0) {
        // 使用标准 scroll-spy 模式：有效区域为视口顶部 ~30% 高度
        // 当标题 top 进入此区域时标记为活跃
        observer = new IntersectionObserver(
          (entries) => {
            // 收集所有当前与该区域相交（或刚刚离开顶部）的标题
            const candidates = [];
            for (const entry of entries) {
              if (entry.isIntersecting) {
                candidates.push({ id: entry.target.id, top: entry.boundingClientRect.top });
              }
            }
            // 如果没有相交的标题，找出最接近顶部（已滚出顶部）的那个
            if (candidates.length === 0) {
              let bestId = null;
              let bestDist = Infinity;
              for (const entry of entries) {
                const dist = Math.abs(entry.boundingClientRect.top - 64); // 64 = header 高度
                if (dist < bestDist) {
                  bestDist = dist;
                  bestId = entry.target.id;
                }
              }
              if (bestId) setActiveId(bestId);
              return;
            }
            // 取最接近顶部（但仍在有效区域内）的标题
            candidates.sort((a, b) => a.top - b.top);
            setActiveId(candidates[0].id);
          },
          {
            rootMargin: '-64px 0px -70% 0px', // 有效区域：header 下方 ~30% 视口高度
            threshold: 0,
          }
        );

        elements.forEach((el) => observer.observe(el));

        // 如果还有未找到的元素，继续轮询并添加
        if (elements.length < allIds.length && retryCount < MAX_RETRIES) {
          retryCount++;
          timerId = setTimeout(() => {
            if (!observer) return;
            const remaining = allIds
              .map((id) => document.getElementById(id))
              .filter(Boolean)
              .filter((el) => !elements.includes(el));
            remaining.forEach((el) => observer.observe(el));
          }, 200);
        }
      }
    };

    // 延迟启动，给 ReactMarkdown 一些时间渲染
    const initTimer = setTimeout(setupObserver, 150);

    return () => {
      clearTimeout(initTimer);
      if (timerId) clearTimeout(timerId);
      if (observer) observer.disconnect();
    };
  }, [allIds]);

  // 监听用户手动滚动 TOC 容器，标记用户主动操作
  useEffect(() => {
    const container = tocRef.current;
    if (!container) return;

    const handleTocScroll = () => {
      userScrollingToc.current = true;
      if (userScrollTimer.current) clearTimeout(userScrollTimer.current);
      userScrollTimer.current = setTimeout(() => {
        userScrollingToc.current = false;
      }, 3000);
    };

    container.addEventListener('scroll', handleTocScroll, { passive: true });
    return () => {
      container.removeEventListener('scroll', handleTocScroll);
      if (userScrollTimer.current) clearTimeout(userScrollTimer.current);
    };
  }, []);

  // activeId 变化时，自动滚动 TOC 容器使活跃项居中（除非用户正在手动滚动）
  useEffect(() => {
    if (!activeId || !tocRef.current) return;
    // 如果用户 3 秒内手动滚动过 TOC，不自动跟随
    if (userScrollingToc.current) return;

    const container = tocRef.current;
    const activeEl = container.querySelector('.toc-item.active');
    if (activeEl) {
      const containerRect = container.getBoundingClientRect();
      const elRect = activeEl.getBoundingClientRect();
      const offsetTop = elRect.top - containerRect.top + container.scrollTop;
      const targetScroll = offsetTop - containerRect.height / 3;
      container.scrollTo({ top: targetScroll, behavior: 'smooth' });
    }
  }, [activeId]);

  // 点击 TOC 项平滑滚动（带 DOM 重试）
  const handleClick = useCallback((id) => {
    const tryScroll = (retries) => {
      const el = document.getElementById(id);
      if (el) {
        el.scrollIntoView({ behavior: 'smooth', block: 'start' });
        return;
      }
      if (retries > 0) {
        setTimeout(() => tryScroll(retries - 1), 50);
      }
    };
    tryScroll(10);
  }, []);

  // 切换折叠状态
  const toggleCollapse = useCallback((id) => {
    setCollapsedMap((prev) => ({ ...prev, [id]: !prev[id] }));
  }, []);

  const containerStyle = useMemo(() => ({
    position: 'fixed',
    top: '80px',
    left: `${sidebarLeft}px`,
    width: '220px',
    maxHeight: 'calc(100vh - 100px)',
    overflowY: 'auto',
    background: 'var(--bg-card)',
    padding: '20px',
    border: '1px solid var(--border)',
    fontSize: '0.9rem',
    zIndex: 10,
  }), [sidebarLeft]);

  if (headings.length === 0) {
    return (
      <div ref={placeholderRef} style={{ width: '220px', flexShrink: 0 }}>
        <div ref={tocRef} style={containerStyle}>
          <div className="toc-header">文章目录</div>
          <div style={{ color: 'var(--text-faint)', fontSize: '0.8rem' }}>暂无目录</div>
        </div>
      </div>
    );
  }

  return (
    <div ref={placeholderRef} style={{ width: '220px', flexShrink: 0 }}>
      <div ref={tocRef} style={containerStyle}>
        <div className="toc-header">文章目录</div>
        <ul className="toc-list">
          {groups.map((group, gi) => {
            const hasHeading = !!group.heading;
            const groupId = hasHeading ? group.heading.id : `group-${gi}`;
            const isCollapsed = hasHeading ? collapsedMap[group.heading.id] : false;

            return (
              <li key={groupId} className="toc-group">
                {hasHeading ? (
                  <>
                    <div
                      className={`toc-item toc-level-1${activeId === group.heading.id ? ' active' : ''}`}
                      style={{ display: 'flex', alignItems: 'center' }}
                      onClick={() => handleClick(group.heading.id)}
                    >
                      <span
                        className={`toc-collapse-btn${isCollapsed ? ' collapsed' : ''}`}
                        onClick={(e) => {
                          e.stopPropagation();
                          toggleCollapse(group.heading.id);
                        }}
                      >
                        ▼
                      </span>
                      <span>{group.heading.text}</span>
                    </div>
                    {group.children.length > 0 && (
                      <div
                        className="toc-group-children"
                        style={{ maxHeight: isCollapsed ? '0px' : `${group.children.length * 40}px` }}
                      >
                        {group.children.map((child, ci) => (
                          <div
                            key={`${child.id}-${ci}`}
                            className={`toc-item toc-level-${child.level}${activeId === child.id ? ' active' : ''}`}
                            onClick={() => handleClick(child.id)}
                          >
                            {child.text}
                          </div>
                        ))}
                      </div>
                    )}
                  </>
                ) : (
                  group.children.map((child, ci) => (
                    <div
                      key={`${child.id}-${ci}`}
                      className={`toc-item toc-level-${child.level}${activeId === child.id ? ' active' : ''}`}
                      onClick={() => handleClick(child.id)}
                    >
                      {child.text}
                    </div>
                  ))
                )}
              </li>
            );
          })}
        </ul>
      </div>
    </div>
  );
};

