const PostDetail = () => {
  const { konamiUnlocked } = React.useContext(ThemeContext);
  const params = useParams();
  const contentRef = useRef(null);
  const rawId = params['*'] ? `${params.id}/${params['*']}` : params.id;
  const id = rawId ? decodeURIComponent(rawId) : '';
  const article = postList.find(a => a.id === id);
  const [content, setContent] = useState('');
  const [toc, setToc] = useState([]);
  const navigablePosts = useMemo(() => {
    return konamiUnlocked ? postList : postList.filter(p => !(p.tags && p.tags.includes('hidden')));
  }, [konamiUnlocked]);
  const currentIndex = navigablePosts.findIndex(a => a.id === id);
  const prevArticle = currentIndex > 0 ? navigablePosts[currentIndex - 1] : null;
  const nextArticle = currentIndex < navigablePosts.length - 1 ? navigablePosts[currentIndex + 1] : null;
  const { popup, addHighlight, closePopup, clearAllHighlights } = useTextHighlighter(contentRef);

  const markdownComponents = useMemo(() => ({
    code({ node, inline, className, children, ...props }) {
      const match = /language-webgpu-live/.exec(className || '');
      if (!inline && match) {
        const codeStr = String(children).replace(/\n$/, '');
        const stableKey = node?.position?.start?.offset ?? Math.random();
        return (
          <div key={`webgpu-${stableKey}`}>
            <pre className={className} {...props}>
              <code>{codeStr}</code>
            </pre>
            <WebGPURunner code={codeStr} />
          </div>
        );
      }
      return (
        <code className={className} {...props}>
          {children}
        </code>
      );
    },
    img: ({node, ...props}) => {
      const imgSrc = props.src.startsWith('http') ? props.src : process.env.PUBLIC_URL + props.src;
      return <img {...props} src={imgSrc} alt={props.alt || ''} style={{ maxWidth: '100%', display: 'block', margin: '20px auto', border: '1px solid var(--border)' }} />;
    }
  }), []);

  useEffect(() => {
    if (article) {
      const encodedPath = id.split('/').map(encodeURIComponent).join('/');
      fetch(`${process.env.PUBLIC_URL}/posts/${encodedPath}.md`)
        .then(res => { if (!res.ok) throw new Error(`HTTP ${res.status}`); return res.text(); })
        .then(text => { const pureMarkdown = stripFrontmatter(text); setContent(pureMarkdown); setToc(extractHeadings(pureMarkdown)); })
        .catch(err => console.error("读取 Markdown 失败", err));
      window.scrollTo(0, 0);
    }
  }, [id, article]);

  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') return;
      if (e.key === 'ArrowLeft' && prevArticle) window.location.hash = `/post/${encodePath(prevArticle.id)}`;
      if (e.key === 'ArrowRight' && nextArticle) window.location.hash = `/post/${encodePath(nextArticle.id)}`;
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [prevArticle, nextArticle]);

  if (!article) return <div style={{ textAlign: 'center', marginTop: '50px' }}>文章未找到</div>;
  const parentPath = getParentPath(id);

  const handlePrint = () => {
    document.body.classList.add('printing');
    window.print();
    document.body.classList.remove('printing');
  };

  return (
    <div style={{ display: 'flex', maxWidth: '1000px', margin: '0 auto', gap: '40px', alignItems: 'flex-start' }}>
      {/* 左侧边栏：TOC + 同分类 */}
      <aside className="desktop-toc-left" style={{ width: '220px', flexShrink: 0, position: 'relative' }}>
        <TOC headings={toc} />

        {article.category && (() => {
          const related = postList.filter(p => p.category === article.category && p.id !== article.id);
          if (related.length === 0) return null;
          return (
            <div style={{ marginTop: '16px', background: 'var(--bg-card)', padding: '16px', border: '1px solid var(--border)', fontSize: '0.9rem' }}>
              <h4 style={{ marginBottom: '12px', color: 'var(--text-primary)', fontWeight: 'bold', fontSize: '0.95rem' }}>同分类</h4>
              {related.slice(0, 5).map(p => (
                <Link key={p.id} to={`/post/${encodePath(p.id)}`} style={{ display: 'block', padding: '6px 0', fontSize: '0.85rem', color: 'var(--text-light)', borderBottom: '1px solid var(--border-light)' }}>{p.title}</Link>
              ))}
            </div>
          );
        })()}
      </aside>

      <div className="card" style={{ flex: '1', minWidth: 0, position: 'relative' }}>
        {/* 工具栏 */}
        <div style={{ display: 'flex', gap: '8px', marginBottom: '16px', paddingBottom: '12px', borderBottom: '1px solid var(--border)', flexWrap: 'wrap', alignItems: 'center' }} className="no-print">
          <button onClick={handlePrint} style={{ background: 'var(--bg-card)', border: '1px solid var(--border)', padding: '6px 14px', cursor: 'pointer', fontSize: '0.8rem', color: 'var(--text-light)', transition: 'all 0.2s' }}
            onMouseOver={e => { e.currentTarget.style.borderColor = 'var(--accent)'; e.currentTarget.style.color = 'var(--accent)'; }}
            onMouseOut={e => { e.currentTarget.style.borderColor = 'var(--border)'; e.currentTarget.style.color = 'var(--text-light)'; }}>
            导出 PDF
          </button>
          <button onClick={clearAllHighlights} style={{ background: 'var(--bg-card)', border: '1px solid var(--border)', padding: '6px 14px', cursor: 'pointer', fontSize: '0.8rem', color: 'var(--text-light)', transition: 'all 0.2s' }}
            onMouseOver={e => { e.currentTarget.style.borderColor = 'var(--accent)'; e.currentTarget.style.color = 'var(--accent)'; }}
            onMouseOut={e => { e.currentTarget.style.borderColor = 'var(--border)'; e.currentTarget.style.color = 'var(--text-light)'; }}>
            清除标注
          </button>
        </div>

        <div style={{ fontSize: '0.8rem', color: 'var(--text-faint)', marginBottom: '16px' }}>
          <Link to="/" style={{ color: 'var(--text-light)' }}>首页</Link>
          {parentPath && <span> / <span style={{ color: 'var(--text-light)' }}>{parentPath}</span></span>}
          <span> / <span style={{ color: 'var(--accent)' }}>{article.title}</span></span>
        </div>
        <h1 style={{ fontSize: '2rem', marginBottom: '10px', color: 'var(--text-primary)' }}>{article.title}</h1>
        <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap', marginBottom: '12px' }}>
          {article.category && <span className="category-badge">{article.category}</span>}
          {article.tags && article.tags.map(tag => <span key={tag} className="tag" style={{ cursor: 'default' }}>{tag}</span>)}
        </div>
        <div style={{ color: 'var(--text-faint)', fontSize: '0.9rem', marginBottom: '30px', borderBottom: '1px solid var(--border)', paddingBottom: '20px' }}>
          发布于 {formatDate(article.date)}
        </div>

        <div className="markdown-body" ref={contentRef}>
          <ReactMarkdown
            remarkPlugins={[remarkMath, remarkGfm]}
            rehypePlugins={[rehypeSlug, rehypeKatex]}
            components={markdownComponents}
          >
            {content}
          </ReactMarkdown>
        </div>

        <div className="nav-buttons">
          {prevArticle ? (
            <Link to={`/post/${encodePath(prevArticle.id)}`} className="nav-button" style={{ textDecoration: 'none' }}>
              <div className="nav-button-label">上一篇</div>
              <div className="nav-button-title">{prevArticle.title}</div>
              <div style={{ fontSize: '0.75rem', color: 'var(--text-faint)', marginTop: '2px' }}>{formatDate(prevArticle.date)}</div>
            </Link>
          ) : <div className="nav-button disabled"><div className="nav-button-label">上一篇</div><div className="nav-button-title" style={{ color: 'var(--text-placeholder)' }}>已是第一篇文章</div></div>}
          {nextArticle ? (
            <Link to={`/post/${encodePath(nextArticle.id)}`} className="nav-button next" style={{ textDecoration: 'none' }}>
              <div className="nav-button-label">下一篇</div>
              <div className="nav-button-title">{nextArticle.title}</div>
              <div style={{ fontSize: '0.75rem', color: 'var(--text-faint)', marginTop: '2px' }}>{formatDate(nextArticle.date)}</div>
            </Link>
          ) : <div className="nav-button next disabled"><div className="nav-button-label">下一篇</div><div className="nav-button-title" style={{ color: 'var(--text-placeholder)' }}>已是最后一篇文章</div></div>}
        </div>
        <div style={{ textAlign: 'center', marginTop: '12px', fontSize: '0.75rem', color: 'var(--text-placeholder)' }}>
          键盘快捷键：上一篇 / 下一篇
        </div>
        <div style={{ marginTop: '20px', textAlign: 'center' }}>
          <Link to="/" style={{ color: 'var(--accent)', fontWeight: 'bold' }}>返回首页</Link>
        </div>

        {/* 弹出标注颜色选择器 */}
        {popup.show && (
          <div className="highlight-popup" style={{ left: popup.x, top: popup.y }}>
            {HIGHLIGHT_COLORS.map(c => (
              <button key={c.value} title={c.name} style={{ background: c.value }}
                onClick={() => addHighlight(c.value)} />
            ))}
            <button className="clear-btn" onClick={closePopup}>x</button>
          </div>
        )}
      </div>

      <style>{`
        @media (min-width: 800px) { .desktop-toc-left { display: block !important; } }
        @media (max-width: 799px) { .desktop-toc-left { display: none; } }
        @media print {
          body.printing .no-print { display: none !important; }
          body.printing .sidebar { display: none !important; }
          body.printing .desktop-toc-left { display: none !important; }
          body.printing .nav-buttons { display: none !important; }
          body.printing footer { display: none !important; }
          body.printing header { display: none !important; }
          body.printing nav { display: none !important; }
          body.printing .theme-toggle { display: none !important; }
          body.printing .home-layout { max-width: 100% !important; }
          body.printing .card { border: none !important; box-shadow: none !important; padding: 0 !important; }
          body.printing .post-detail { max-width: 100% !important; }
          body.printing .markdown-body { font-size: 12pt !important; }
          body.printing mark { background: #ffeb3b !important; color: #000 !important; }
          body.printing { background: white !important; }
          body.printing * { background: transparent !important; color: #000 !important; }
          body.printing a { text-decoration: underline !important; }
          body.printing h1, body.printing h2, body.printing h3, body.printing h4 { page-break-after: avoid; orphans: 3; widows: 3; }
          body.printing p, body.printing li, body.printing blockquote, body.printing pre { orphans: 2; widows: 2; }
          body.printing pre, body.printing table, body.printing img { page-break-inside: avoid; }
        }
        .markdown-body mark { transition: opacity 0.2s; }
        .markdown-body mark:hover { opacity: 0.7; }
      `}</style>
    </div>
  );
};

