// ==================== Konami Code ====================
const KONAMI_SEQUENCE = ['ArrowUp', 'ArrowUp', 'ArrowDown', 'ArrowDown', 'ArrowLeft', 'ArrowRight', 'ArrowLeft', 'ArrowRight', 'b', 'a'];

const useKonamiCode = (onActivate) => {
  const seqRef = useRef(0);
  const timerRef = useRef(null);
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') return;
      if (e.isComposing || e.key === 'Process') return;
      const expected = KONAMI_SEQUENCE[seqRef.current];
      let matched = false;
      if (expected === 'b' || expected === 'a') {
        matched = e.code === `Key${expected.toUpperCase()}`;
      } else if (typeof expected === 'string' && expected.length === 1) {
        matched = e.key.toLowerCase() === expected;
      } else {
        matched = e.key === expected;
      }
      if (matched) {
        seqRef.current += 1;
        if (seqRef.current === KONAMI_SEQUENCE.length) { seqRef.current = 0; onActivate(); return; }
        clearTimeout(timerRef.current);
        timerRef.current = setTimeout(() => { seqRef.current = 0; }, 2000);
      } else { seqRef.current = 0; }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => { window.removeEventListener('keydown', handleKeyDown); clearTimeout(timerRef.current); };
  }, [onActivate]);
};

