// ==================== 密码解锁弹窗组件 ====================
const PasswordDialog = ({ show, onUnlock, onClose }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const inputRef = useRef(null);

  useEffect(() => {
    if (show && inputRef.current) {
      inputRef.current.focus();
      setPassword('');
      setError('');
      setSuccess('');
    }
  }, [show]);

  if (!show) return null;

  const handleSubmit = async () => {
    if (!password.trim()) {
      setError('请输入密码');
      return;
    }
    try {
      const result = await onUnlock(password.trim());
      if (result) {
        setSuccess('解锁成功！');
        setTimeout(() => onClose(), 1200);
      } else {
        setError('密码错误，请重试');
      }
    } catch (err) {
      setError('解密失败: ' + err.message);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') handleSubmit();
  };

  return (
    <div className="password-dialog-overlay" onClick={onClose}>
      <div className="password-dialog" onClick={e => e.stopPropagation()}>
        <h2>🔒 解锁私密文章</h2>
        <p>
          共 {encryptedPostsData.length} 篇加密文章，输入密码解锁后即可在首页查看。
        </p>
        <div className="password-input-group">
          <input
            ref={inputRef}
            type="password"
            placeholder="请输入密码"
            value={password}
            onChange={e => setPassword(e.target.value)}
            onKeyDown={handleKeyDown}
          />
          <button onClick={handleSubmit}>解锁</button>
        </div>
        {error && <div className="password-error">{error}</div>}
        {success && <div className="password-success">{success}</div>}
      </div>
    </div>
  );
};

// ==================== 4. 根组件 ====================
export default function App() {
  const [theme, setTheme] = useState(() => { try { return localStorage.getItem('blog-theme') || 'light'; } catch { return 'light'; } });
  const [konamiUnlocked, setKonamiUnlocked] = useState(() => { try { return localStorage.getItem('blog-konami') === 'true'; } catch { return false; } });
  const [showPasswordDialog, setShowPasswordDialog] = useState(false);
  const [decryptedPosts, setDecryptedPosts] = useState([]);
  const [isDecrypting, setIsDecrypting] = useState(false);

  const handleKonamiActivate = useCallback(() => {
    setKonamiUnlocked(prev => { const next = !prev; try { localStorage.setItem('blog-konami', next); } catch { } return next; });
  }, []);

  useKonamiCode(handleKonamiActivate);

  const toggleTheme = useCallback(() => {
    setTheme(prev => { const next = prev === 'dark' ? 'light' : 'dark'; try { localStorage.setItem('blog-theme', next); } catch { } return next; });
  }, []);

  // 当 Konami 解锁时，如果有加密文章且尚未解密，弹出密码框
  useEffect(() => {
    if (konamiUnlocked && encryptedPostsData.length > 0 && decryptedPosts.length === 0 && !isDecrypting) {
      setShowPasswordDialog(true);
    }
  }, [konamiUnlocked, decryptedPosts.length, isDecrypting]);

  // 密码解锁处理
  const handleUnlock = useCallback(async (password) => {
    setIsDecrypting(true);
    try {
      const promises = encryptedPostsData.map(async (ep) => {
        const content = await decryptContent(password, ep.encrypted);
        return {
          id: ep.id,
          category: ep.category,
          tags: ep.tags,
          title: ep.title,
          date: ep.date,
          summary: ep.summary,
          decryptedContent: content,
        };
      });
      const results = await Promise.all(promises);
      setDecryptedPosts(results);
      setIsDecrypting(false);
      return true;
    } catch (err) {
      setIsDecrypting(false);
      // AES-GCM 解密失败通常意味着密码错误
      return false;
    }
  }, []);

  const ctxValue = useMemo(() => ({
    theme,
    toggleTheme,
    konamiUnlocked,
    decryptedPosts,
    setShowPasswordDialog,
  }), [theme, toggleTheme, konamiUnlocked, decryptedPosts]);

  return (
    <ThemeContext.Provider value={ctxValue}>
      <Router>
        <style>{customStyles}</style>
        <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column' }}>
          <Header />
          <main style={{ padding: '40px 20px', width: '100%', flex: '1' }}>
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/post/:id/*" element={<PostDetail />} />
              <Route path="/about" element={<About />} />
            </Routes>
          </main>
          <footer style={{ textAlign: 'center', padding: '24px', color: 'var(--text-faint)', fontSize: '0.875rem' }}>
            (C) {new Date().getFullYear()} 个人技术博客 · 构建于 React · 共 {postList.length} 篇文章
          </footer>
        </div>
      </Router>

      {/* 密码解锁对话框 */}
      <PasswordDialog
        show={showPasswordDialog}
        onUnlock={handleUnlock}
        onClose={() => setShowPasswordDialog(false)}
      />
    </ThemeContext.Provider>
  );
}
