import React, { useEffect, useRef, useState, useCallback } from 'react';

const WebGPURunner = ({ code }) => {
  const canvasRef = useRef(null);
  const containerRef = useRef(null);
  const [status, setStatus] = useState('idle'); 
  const [runId, setRunId] = useState(0); 
  const gpuDeviceRef = useRef(null);
  const frameIdRef = useRef(null);
  
  // 使用一个专门的 Ref 记录当前正在运行的 ID，防止异步竞争
  const currentExecutionId = useRef(0);

  const handleRun = useCallback((e) => {
    e.stopPropagation();
    currentExecutionId.current += 1;
    setRunId(currentExecutionId.current);
    setStatus('running');
  }, []);

  const resetToIdle = useCallback((e) => {
    if (e) e.stopPropagation();
    stopAll();
    setStatus('idle');
  }, []);

  const stopAll = () => {
    if (frameIdRef.current) {
      cancelAnimationFrame(frameIdRef.current);
      frameIdRef.current = null;
    }
    if (gpuDeviceRef.current) {
      gpuDeviceRef.current.destroy();
      gpuDeviceRef.current = null;
    }
  };

  useEffect(() => {
    return () => {
      stopAll();
    };
  }, []);

  useEffect(() => {
    if (runId === 0) return;

    // 1. 获取 Canvas 实例
    const canvas = canvasRef.current;
    if (!canvas) return;

    // 清除旧的错误信息
    const container = containerRef.current;
    if (container) {
      container.querySelectorAll('.webgpu-error').forEach(el => el.remove());
    }

    // 2. 环境检查
    if (!navigator.gpu) {
      setStatus('error');
      showError('⚠️ 您的浏览器不支持 WebGPU');
      return;
    }

    // 3. 准备资源清理和动画控制
    const thisRunId = runId;
    let isCancelled = false;

    const controller = {
      shouldStop: () => isCancelled || thisRunId !== currentExecutionId.current,
      registerFrame: (id) => {
        frameIdRef.current = id;
      },
    };

    const start = async () => {
      try {
        // 配置分辨率
        const dpr = window.devicePixelRatio || 1;
        const rect = canvas.getBoundingClientRect();
        canvas.width = rect.width * dpr;
        canvas.height = rect.height * dpr;

        const adapter = await navigator.gpu.requestAdapter();
        if (!adapter) throw new Error('无法获取 GPU 适配器');

        const device = await adapter.requestDevice();
        gpuDeviceRef.current = device;

        if (controller.shouldStop()) {
          device.destroy();
          return;
        }

        // 核心：这里的参数名必须和用户代码中使用的变量名一致 (canvas, device, controller)
        const AsyncFunction = Object.getPrototypeOf(async function () { }).constructor;
        const execute = new AsyncFunction('canvas', 'device', 'controller', code);
        
        await execute(canvas, device, controller);

        if (!controller.shouldStop()) {
          setStatus('success');
        }
      } catch (err) {
        if (!controller.shouldStop()) {
          console.error('WebGPU Error:', err);
          setStatus('error');
          showError(`运行错误: ${err.message}`);
        }
      }
    };

    function showError(text) {
        if (!container) return;
        const errorEl = document.createElement('pre');
        errorEl.className = 'webgpu-error';
        errorEl.style.cssText = 'color:#ff5555;padding:12px;margin:8px;font-size:0.85rem;background:#1a1a1a;overflow-x:auto;white-space:pre-wrap;';
        errorEl.textContent = text;
        container.appendChild(errorEl);
    }

    start();

    return () => {
      isCancelled = true;
    };
  }, [runId, code]);

  return (
    <div style={{ margin: '16px 0', position: 'relative' }}>
      {/* 控制按钮区 */}
      <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '8px', gap: '10px' }}>
        {status === 'idle' ? (
          <button onClick={handleRun} style={buttonStyle}>▶ 运行 WebGPU</button>
        ) : (
          <button onClick={resetToIdle} style={{...buttonStyle, borderColor: '#666', color: '#999'}}>⏹ 停止并重置</button>
        )}
      </div>

      {/* 渲染容器：始终在 DOM 中，通过 display 控制 */}
      <div
        ref={containerRef}
        style={{
          display: status === 'idle' ? 'none' : 'block',
          border: '1px solid #333',
          borderRadius: '8px',
          overflow: 'hidden',
          background: '#000',
        }}
      >
        <canvas
          ref={canvasRef}
          style={{
            width: '100%',
            display: 'block',
            aspectRatio: '16 / 9',
          }}
        />
        
        {/* 状态栏 */}
        <div style={statusBarStyle}>
          {status === 'running' && <span>⏳ 正在初始化...</span>}
          {status === 'success' && <span style={{color: '#4caf50'}}>✅ 运行成功</span>}
          {status === 'error' && <span style={{color: '#ff5555'}}>❌ 运行出错</span>}
          <span style={{ marginLeft: 'auto', opacity: 0.6 }}>WebGPU Live Preview</span>
        </div>
      </div>
    </div>
  );
};

// 样式常量
const buttonStyle = {
  padding: '8px 20px',
  background: 'transparent',
  border: '1px solid #4f46e5',
  borderRadius: '6px',
  cursor: 'pointer',
  fontSize: '0.85rem',
  fontWeight: 600,
  color: '#4f46e5',
};

const statusBarStyle = {
  padding: '8px 14px',
  fontSize: '0.75rem',
  background: '#111',
  color: '#eee',
  display: 'flex',
  alignItems: 'center',
  gap: '8px',
  borderTop: '1px solid #222'
};

export default WebGPURunner;